import{_ as a,o as s,c as n,a as o}from"./chunks/framework.8tiMeCK-.js";const g=JSON.parse('{"title":"7.2  用户空间与邻居子系统的交互","description":"","frontmatter":{},"headers":[],"relativePath":"notes/linux_kernel_networking/ch07_2.md","filePath":"notes/linux_kernel_networking/ch07_2.md","lastUpdated":null}'),d={name:"notes/linux_kernel_networking/ch07_2.md"};function p(i,e,c,t,r,l){return s(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="_7-2-用户空间与邻居子系统的交互" tabindex="-1">7.2 用户空间与邻居子系统的交互 <a class="header-anchor" href="#_7-2-用户空间与邻居子系统的交互" aria-label="Permalink to &quot;7.2  用户空间与邻居子系统的交互&quot;">​</a></h1><p>上一节我们聊了邻居子系统内部的那些「家务事」：内存怎么分、引用计数怎么管、条目什么时候销毁。如果你是内核开发者，这些就是你的砖瓦和水泥。</p><p>但如果你是系统管理员，或者只是在调试网络问题的开发者，你其实并不直接跟这些结构体打交道。你手里拿的是 <code>iproute2</code> 工具箱，你敲的是 <code>ip neigh</code>。这之间隔着一层 API。这一节就是关于这层 API 的——我们如何从用户空间去窥探、修改、甚至强行「教唆」内核的邻居表。</p><hr><h2 id="命令行工具-从-net-tools-到-iproute2" tabindex="-1">命令行工具：从 net-tools 到 iproute2 <a class="header-anchor" href="#命令行工具-从-net-tools-到-iproute2" aria-label="Permalink to &quot;命令行工具：从 net-tools 到 iproute2&quot;">​</a></h2><p>管理 ARP 表（或者说邻居表）的方式主要有两种，代表了两个时代的风格：</p><ol><li><strong>老派做法</strong>：使用 <code>net-tools</code> 包里的 <code>arp</code> 命令。</li><li><strong>新派做法</strong>：使用 <code>iproute2</code> 包里的 <code>ip neigh</code>（或 <code>ip neighbour</code>）命令。</li></ol><p>虽然它们干的是同一件事，但底层走的路径完全不同。</p><p>如果你运行经典的 <code>arp</code> 命令：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ arp</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这个请求最终会由内核里的 <code>arp_seq_show()</code> 方法处理，代码在 <code>net/ipv4/arp.c</code> 里。注意，这是 IPv4 专用的——它只看得到 ARP 表。</p><p>如果你运行现代的 <code>ip neigh show</code>：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ ip neigh show</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这回调用的是通用的 <code>neigh_dump_info()</code> 方法，位于 <code>net/core/neighbour.c</code>。</p><p>这两者输出最大的区别在于信息量。<code>arp</code> 命令给的是一个简略的列表，而 <code>ip neigh show</code> 会把邻居条目的 <strong>NUD 状态</strong>（Neighbour Unreachability Detection，邻居不可达检测状态）一股脑儿倒给你——比如 <code>NUD_REACHABLE</code>（可达）、<code>NUD_STALE</code>（陈旧）、<code>NUD_DELAY</code>（延迟）等。这些状态其实是邻居子系统的「体温计」，我们在后面几章会重点讲。</p><p>此外，<code>ip</code> 命令是双模的。加上 <code>-6</code> 参数：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ ip -6 neigh show</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>它就会去显示 IPv6 的邻居表（NDISC 表）。这是 <code>arp</code> 命令做不到的。</p><p>除了命令行，内核还通过 <code>procfs</code> 暴露了这些数据。如果你是一个习惯了 <code>cat</code> 文件的古老管理员，你依然可以这样操作：</p><ul><li><strong>看 ARP 表</strong>：<code>cat /proc/net/arp</code>。这背后其实还是调用的 <code>arp_seq_show()</code>，跟敲 <code>arp</code> 命令没本质区别。</li><li><strong>看统计信息</strong>：<code>cat /proc/net/stat/arp_cache</code>（ARP 统计）或 <code>cat /proc/net/stat/ndisc_cache</code>（NDISC 统计）。这两个文件由 <code>neigh_stat_seq_show()</code> 方法统一处理。</li></ul><hr><h2 id="手动增删-教内核做规矩" tabindex="-1">手动增删：教内核做规矩 <a class="header-anchor" href="#手动增删-教内核做规矩" aria-label="Permalink to &quot;手动增删：教内核做规矩&quot;">​</a></h2><p>通常情况下，内核自己会动态学习邻居的 MAC 地址（被动学习）。但有时候，我们想强行告诉内核某件事——比如「192.168.0.121 永远在 00:30:48:5b:cc:45」，不管它实际在不在。这就是<strong>静态邻居条目</strong>。</p><p>你可以用 <code>ip neigh add</code> 来做这件事：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ ip neigh add 192.168.0.121 dev eth0 lladdr 00:30:48:5b:cc:45 nud permanent</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这条命令会触发 <code>neigh_add()</code> 方法。注意最后那个 <code>nud permanent</code>，我们在上一节提到的 <code>NUD_PERMANENT</code> 状态就在这里派上用场了。这个状态告诉内核：「这条条目别删，别改，别过期，它是铁律。」</p><p>要删掉它，用 <code>ip neigh del</code>，这背后是 <code>neigh_delete()</code> 方法：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ ip neigh del 192.168.0.121 dev eth0</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>还有一个很有用的场景是 <strong>Proxy ARP（代理 ARP）</strong>。</p><p>简单回忆一下这个概念：主机 A 询问「谁有 IP B？」，主机 C（路由器）虽然不是 IP B，但它可以代替 B 回答「我有，MAC 是 xxx」，然后把流量收过来再转发给 B。这在某些特殊网络拓扑里很有用。</p><p>要在内核里配置一个代理 ARP 条目，用 <code>proxy</code> 关键字：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ ip neigh add proxy 192.168.2.11 dev eth0</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>虽然命令看起来差不多，但内核内部走的路径完全不一样。<code>neigh_add()</code> 方法会发现用户传进来的数据里带了一个 <code>NTF_PROXY</code> 标志（存储在 <code>ndm</code> 对象的 <code>ndm_flags</code> 字段里）。一旦看到这个标志，内核就不会去查普通的邻居表，而是调用 <code>pneigh_lookup()</code> 方法去查<strong>代理邻居哈希表</strong>（<code>phash_buckets</code>）。如果没查到，它就会在这个表里新增一个条目。</p><p>删除代理条目也是同理：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ ip neigh del proxy 192.168.2.11 dev eth0</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><code>neigh_delete()</code> 方法检测到 <code>NTF_PROXY</code> 标志后，会调用 <code>pneigh_delete()</code> 来清理代理表。</p><p>除了操作条目，你还可以操作整个表的参数。<code>ip ntable</code> 命令就是干这个的：</p><ul><li><p><code>ip ntable show</code>：显示所有邻居表的参数配置。</p></li><li><p><code>ip ntable change</code>：动态修改参数。比如，把 <code>eth0</code> 接口上的 ARP 缓存队列长度改为 20：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ ip ntable change name arp_cache queue 20 dev eth0</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这会调用 <code>neightbl_set()</code> 方法。这对于调优大量邻居场景（比如数据中心网关）非常有用。</p></li></ul><p>最后提一句老古董 <code>arp</code> 命令。你也可以用它来加静态条目：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ arp -s &lt;IPAddress&gt; &lt;MacAddress&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>效果跟 <code>ip neigh add ... nud permanent</code> 类似，但千万别指望静态条目能在重启后保留——它们只活在内核内存里，一断电就没了。如果想要持久化，得写进启动脚本里。</p><hr><h2 id="网络事件的回调-内核的耳朵" tabindex="-1">网络事件的回调：内核的耳朵 <a class="header-anchor" href="#网络事件的回调-内核的耳朵" aria-label="Permalink to &quot;网络事件的回调：内核的耳朵&quot;">​</a></h2><p>搞定了用户空间怎么敲门，我们再看看内核内部怎么听「广播」。</p><p>这里的「广播」指的是网络事件通知。</p><p>有意思的是，<strong>邻居核心子系统本身是不注册网络事件通知的</strong>。它是一个安静的核心，不直接关心网卡的插拔或 MAC 变更。真正操心这些事的是具体的协议模块——ARP 和 NDISC。</p><p>在 IPv4 的 ARP 模块里，<code>arp_netdev_event()</code> 被注册为网络事件的回调函数。它主要盯着两类事：</p><ol><li><strong>MAC 地址变了</strong>：比如你在网卡上敲了 <code>ifconfig eth0 hw ether ...</code>。此时内核会触发事件，<code>arp_netdev_event()</code> 会调用通用的 <code>neigh_changeaddr()</code> 方法来刷掉相关的邻居条目，同时调用 <code>rt_cache_flush()</code> 清空路由缓存。因为 L2 地址变了，之前的缓存可能全都不对了。</li><li><strong>标志位变了（从 3.11 内核开始）</strong>：如果网卡的 <code>IFF_NOARP</code> 标志位发生了变化，也会触发 <code>NETDEV_CHANGE</code> 事件。同样的，<code>neigh_changeaddr()</code> 会介入处理。</li></ol><p>而在 IPv6 的 NDISC 模块里，<code>ndisc_netdev_event()</code> 承担了类似的责任，但它关注的信号更多样：<code>NETDEV_CHANGEADDR</code>（地址变更）、<code>NETDEV_DOWN</code>（网卡停机）、以及 <code>NETDEV_NOTIFY_PEERS</code>（通知邻居，通常用于网卡 Failover 场景）。</p><hr><p><strong>本章回响</strong></p><p>这一节我们站在了用户空间和内核空间的边界线上。</p><p>我们看到了同一份数据——邻居表——是如何被不同的视角审视的。对于 <code>iproute2</code>，它是一组可以被 Show、Add、Del 的对象；对于内核，它是一组哈希表、引用计数和状态机。</p><p>更重要的是，我们引入了<strong>静态配置</strong>和<strong>动态事件</strong>这两个概念。虽然手动添加条目看起来很方便，但真正的网络世界是流动的——MAC 会变，网卡会断，流量会迁移。</p><p><strong>（承接下一节）</strong> 现在，我们已经有了容器，也有了管理容器的手段。但容器里依然是空的。下一节，我们将把镜头切入到 IPv4 的世界，看看 <strong>ARP 协议</strong>是如何作为第一个居民，住进这个准备好的房子里的——尤其是那个最核心的问题：当内核发现「我不知道隔壁老王是谁」时，它到底发出了什么信号？</p>',55)])])}const u=a(d,[["render",p]]);export{g as __pageData,u as default};
